// Calcular contexto del checkpoint y fechas para consulta
const now = new Date();

// Ajustar a timezone de Colombia (UTC-5)
const colombiaOffset = -5 * 60;
const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
const colombiaTime = new Date(utc + (colombiaOffset * 60000));

// Obtener fecha actual para el documento
const today = new Date(colombiaTime);
today.setHours(0, 0, 0, 0);
const dateString = today.toISOString().split('T')[0]; // YYYY-MM-DD

// Generar document ID para hoy
const documentId = `HPiS7rrqvKVm9uZBV8sHzW8wQz33_${dateString}`;

// Determinar checkpoint actual y meta correspondiente
const currentHour = colombiaTime.getHours();
const currentMinute = colombiaTime.getMinutes();
let checkpoint = '';
let targetHydration = 0;
let checkpointTime = '';

if (currentHour === 9 && currentMinute === 0) {
  checkpoint = 'morning';
  targetHydration = 500;
  checkpointTime = '9:00am';
} else if (currentHour === 11 && currentMinute === 30) {
  checkpoint = 'late_morning';
  targetHydration = 1000;
  checkpointTime = '11:30am';
} else if (currentHour === 15 && currentMinute === 0) {
  checkpoint = 'afternoon';
  targetHydration = 1500;
  checkpointTime = '3:00pm';
} else if (currentHour === 18 && currentMinute === 0) {
  checkpoint = 'evening';
  targetHydration = 2000;
  checkpointTime = '6:00pm';
} else if (currentHour === 21 && currentMinute === 0) {
  checkpoint = 'night';
  targetHydration = 2500;
  checkpointTime = '9:00pm';
}

// Rango de tiempo para consultar (desde inicio del día hasta ahora)
const startOfDay = new Date(today);
const endOfDay = new Date(colombiaTime);

return {
  documentId: documentId,
  checkpoint: checkpoint,
  targetHydration: targetHydration,
  checkpointTime: checkpointTime,
  currentTime: colombiaTime.toISOString(),
  dateString: dateString,
  startOfDayTimestamp: startOfDay.toISOString(),
  endOfDayTimestamp: endOfDay.toISOString(),
  currentHour: currentHour,
  currentMinute: currentMinute
};

// Analizar datos de hidratación del día
const contextData = $input.first().json;
const firebaseData = $input.last().json;

// Extraer contexto del checkpoint
const {
  checkpoint,
  targetHydration,
  checkpointTime,
  currentTime,
  dateString
} = contextData;

// Procesar datos de Firebase
let drinks = [];
let totalHydration = 0;
let totalAmount = 0;

// Verificar si existe el documento y tiene datos
if (firebaseData && firebaseData.drinks && Array.isArray(firebaseData.drinks)) {
  drinks = firebaseData.drinks;
} else if (Array.isArray(firebaseData) && firebaseData.length > 0 && firebaseData[0].drinks) {
  drinks = firebaseData[0].drinks;
}

// Agrupar bebidas por tipo y calcular totales
const drinksByType = {};
const drinkTimes = [];

drinks.forEach(drink => {
  if (drink && typeof drink === 'object') {
    const type = drink.type || 'unknown';
    const hydration = drink.hydration || 0;
    const amount = drink.amount || 0;
    const time = drink.time || '';

    // Sumar hidratación total
    totalHydration += hydration;
    totalAmount += amount;

    // Agrupar por tipo
    if (!drinksByType[type]) {
      drinksByType[type] = {
        count: 0,
        totalAmount: 0,
        totalHydration: 0,
        times: []
      };
    }

    drinksByType[type].count++;
    drinksByType[type].totalAmount += amount;
    drinksByType[type].totalHydration += hydration;
    drinksByType[type].times.push(time);

    if (time) {
      drinkTimes.push({ time, type, amount, hydration });
    }
  }
});

// Ordenar bebidas por tiempo
drinkTimes.sort((a, b) => a.time.localeCompare(b.time));

// Calcular si necesita hidratación
const hydrationNeeded = targetHydration - totalHydration;
const needsHydration = hydrationNeeded > 0;
const percentage = totalHydration > 0 ? Math.round((totalHydration / targetHydration) * 100) : 0;

// Generar insights sobre patrones de consumo
const insights = {
  hasWater: drinksByType.water ? true : false,
  waterAmount: drinksByType.water?.totalHydration || 0,
  hasCoffee: drinksByType.coffee ? true : false,
  coffeeAmount: drinksByType.coffee?.totalHydration || 0,
  hasJuice: drinksByType.juice ? true : false,
  juiceAmount: drinksByType.juice?.totalHydration || 0,
  totalDrinks: drinks.length,
  uniqueTypes: Object.keys(drinksByType).length,
  lastDrinkTime: drinkTimes.length > 0 ? drinkTimes[drinkTimes.length - 1].time : null,
  firstDrinkTime: drinkTimes.length > 0 ? drinkTimes[0].time : null
};

// Determinar severidad de la falta de hidratación
let severity = 'good';
if (needsHydration) {
  const missingPercentage = (hydrationNeeded / targetHydration) * 100;
  if (missingPercentage >= 60) {
    severity = 'critical';
  } else if (missingPercentage >= 30) {
    severity = 'warning';
  } else {
    severity = 'mild';
  }
}

return [{
  json: {
    // CONTEXTO
    context: {
      checkpoint: checkpoint,
      checkpointTime: checkpointTime,
      targetHydration: targetHydration,
      currentTime: currentTime,
      dateString: dateString
    },

    // ESTADO DE HIDRATACIÓN
    hydrationStatus: {
      totalHydration: totalHydration,
      totalAmount: totalAmount,
      targetHydration: targetHydration,
      hydrationNeeded: hydrationNeeded,
      needsHydration: needsHydration,
      percentage: percentage,
      severity: severity
    },

    // ANÁLISIS POR TIPO DE BEBIDA
    drinksByType: drinksByType,
    drinkTimeline: drinkTimes,

    // INSIGHTS PARA LA IA
    insights: insights,

    // RESUMEN PARA MENSAJE
    summary: {
      totalDrinks: drinks.length,
      typesConsumed: Object.keys(drinksByType),
      mainDrinkType: Object.keys(drinksByType).length > 0 ? 
        Object.entries(drinksByType).reduce((a, b) => 
          drinksByType[a[0]].totalHydration > drinksByType[b[0]].totalHydration ? a : b
        )[0] : null,
      lastDrinkHoursAgo: insights.lastDrinkTime ? 
        Math.round((new Date().getHours() * 60 + new Date().getMinutes() - 
        (parseInt(insights.lastDrinkTime.split(':')[0]) * 60 + 
         parseInt(insights.lastDrinkTime.split(':')[1]))) / 60 * 10) / 10 : null
    }
  }
}];
